```python
# BAD: a module-level dict mutated by tests
_cache = {}
def test_a(): _cache['x'] = 1; assert _cache['x'] == 1
def test_b(): assert _cache.get('x') is None   # fails if test_a ran first

# GOOD: fixture per-test
@pytest.fixture
def cache():
    return {}
def test_a(cache): cache['x'] = 1; assert cache['x'] == 1
def test_b(cache): assert cache.get('x') is None
```
